object Solution { def revenue_by_region(customers: Seq[Map[String, Any]], orders: Seq[Map[String, Any]]): Map[String, Int] = { val regionOf = customers.map(c => asInt(c("id")) -> c("region").toString).toMap; val totals = scala.collection.mutable.Map[String, Int]().withDefaultValue(0); for (order <- orders; region <- regionOf.get(asInt(order("customer_id")))) totals(region) += asInt(order("amount")); totals.toMap }; private def asInt(value: Any): Int = value match { case n: Int => n; case n: Long => n.toInt; case n: Double => n.toInt; case _ => 0 } }
